import React, { useRef, useEffect, useState } from "react";
import { motion } from "framer-motion";

const Gallery = () => {
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);
  const marqueeRef = useRef(null);
  const [activeIndex, setActiveIndex] = useState(0);
  const [visibleStart, setVisibleStart] = useState(0);
  const autoScrollSpeed = 0.8;
  const [pause, setPause] = useState(false);

  // ──────────────────────────────────────────────────────────────
  //  NODE SERVER ENDPOINTS
  // ──────────────────────────────────────────────────────────────
  const API_URL = "http://localhost:5000/api/getData";   // <-- NEW
  const IMAGE_BASE = "http://localhost:5000";           // <-- NEW
  // ──────────────────────────────────────────────────────────────

  // Derived values (safe access)
  const gallery = data?.gallery || [];
  const clients = data?.clients || [];
  const length = gallery.length;
  const maxDots = 50;
  const showPaginated = length > maxDots;
  const dotsToShow = showPaginated ? 10 : length;
  const companyName = data?.companyInfo?.name || "Taj Advertising";
  const tagline = `Premium Advertising Solutions in ${
    data?.companyInfo?.location || "India"
  }`;
  const description = data?.companyInfo?.description || "";

  // ──────────────────────────────────────────────────────────────
  //  FETCH DATA
  // ──────────────────────────────────────────────────────────────
  useEffect(() => {
    fetch(API_URL)
      .then((res) => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then((fetchedData) => {
        console.log("Fetched data:", fetchedData);
        if (fetchedData.error) throw new Error(fetchedData.error);
        setData(fetchedData);
        setError(null);
      })
      .catch((err) => {
        console.error("Fetch error:", err);
        setError(err.message);
        setData(null);
      });
  }, []);

  // ──────────────────────────────────────────────────────────────
  //  DOT PAGINATION
  // ──────────────────────────────────────────────────────────────
  useEffect(() => {
    if (!data || length === 0 || !showPaginated) {
      setVisibleStart(0);
      return;
    }
    const half = Math.floor(dotsToShow / 2);
    let newStart = activeIndex - half;
    newStart = Math.max(0, newStart);
    newStart = Math.min(newStart, length - dotsToShow);
    setVisibleStart(newStart);
  }, [activeIndex, length, dotsToShow, showPaginated, data]);

  // ──────────────────────────────────────────────────────────────
  //  AUTO SCROLL
  // ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const marquee = marqueeRef.current;
    if (!marquee || length === 0) return;
    let frame;

    const scroll = () => {
      if (!pause) {
        marquee.scrollLeft += autoScrollSpeed;
        if (marquee.scrollLeft + marquee.clientWidth >= marquee.scrollWidth) {
          marquee.scrollLeft = 0;
        }
      }
      frame = requestAnimationFrame(scroll);
    };

    frame = requestAnimationFrame(scroll);
    return () => cancelAnimationFrame(frame);
  }, [pause, length]);

  // ──────────────────────────────────────────────────────────────
  //  UPDATE ACTIVE INDEX ON SCROLL
  // ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const marquee = marqueeRef.current;
    if (!marquee || length === 0) return;

    const handler = () => {
      const imgW = marquee.scrollWidth / length;
      const idx = Math.round(marquee.scrollLeft / imgW) % length;
      setActiveIndex(idx);
    };

    marquee.addEventListener("scroll", handler);
    return () => marquee.removeEventListener("scroll", handler);
  }, [length]);

  // ──────────────────────────────────────────────────────────────
  //  HOVER PAUSE
  // ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const marquee = marqueeRef.current;
    if (!marquee) return;
    marquee.addEventListener("mouseenter", () => setPause(true));
    marquee.addEventListener("mouseleave", () => setPause(false));
    return () => {
      marquee.removeEventListener("mouseenter", () => {});
      marquee.removeEventListener("mouseleave", () => {});
    };
  }, []);

  // ──────────────────────────────────────────────────────────────
  //  RENDER
  // ──────────────────────────────────────────────────────────────
  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-white">
        <div className="text-center text-red-500">
          <h2>Error Loading Gallery</h2>
          <p>{error}</p>
          <button
            onClick={() => window.location.reload()}
            className="px-4 py-2 mt-4 text-white bg-blue-600 rounded"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  if (!data) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-white">
        <p className="text-gray-600">Loading Gallery...</p>
      </div>
    );
  }

  const handleDotClick = (idx) => {
    const marquee = marqueeRef.current;
    if (!marquee) return;
    const imgW = marquee.scrollWidth / length;
    setPause(true);
    marquee.scrollTo({ left: imgW * idx, behavior: "smooth" });
    setActiveIndex(idx);
    setTimeout(() => setPause(false), 2500);
  };

  const handlePrev = () => handleDotClick((activeIndex - 1 + length) % length);
  const handleNext = () => handleDotClick((activeIndex + 1) % length);

  const startIdx = showPaginated ? visibleStart : 0;
  const numToShow = showPaginated ? dotsToShow : length;

  return (
    <section id="gallery" className="flex flex-col w-full min-h-screen py-10 bg-white sm:py-16">
      <div className="flex flex-col flex-1 px-4 mx-auto max-w-7xl sm:px-6 lg:px-8">
        {/* Header */}
        <motion.h2
          className="mb-3 text-3xl font-bold text-center text-blue-800 sm:text-4xl md:text-5xl"
          initial={{ y: -50 }}
          whileInView={{ y: 0 }}
          viewport={{ once: true }}
        >
          {companyName}
        </motion.h2>
        <p className="mb-8 text-base text-center text-gray-600 sm:text-lg sm:mb-10">{tagline}</p>

        {/* Marquee */}
        <div
          ref={marqueeRef}
          className="relative flex mb-6 overflow-x-scroll scroll-smooth sm:mb-8 no-scrollbar"
          style={{ scrollBehavior: "smooth" }}
        >
          {gallery.length > 0 ? (
            gallery.map((img, i) => (
              <motion.div
                key={`${img.image}-${i}`}
                className="flex justify-center flex-shrink-0 mx-2 sm:mx-3"
              >
                <motion.img
                  src={`${IMAGE_BASE}/${img.image}`}   // <-- uses /uploads/...
                  alt={img.caption || "Gallery image"}
                  className="object-cover w-48 transition-transform duration-300 rounded-lg shadow-md cursor-pointer h-36 sm:w-64 sm:h-48 md:w-80 md:h-56 lg:w-96 lg:h-64 hover:scale-105"
                  whileHover={{ scale: 1.08, rotate: 1 }}
                  loading="lazy"
                  onError={(e) => {
                    console.error(`Broken image: ${img.image}`);
                    e.target.style.display = "none";
                  }}
                />
              </motion.div>
            ))
          ) : (
            <div className="flex justify-center w-full py-8">
              <p className="text-gray-500">No images in gallery yet.</p>
            </div>
          )}
        </div>

        {/* Dots + Prev/Next */}
        {length > 0 && (
          <div className="flex flex-wrap items-center justify-center mt-2 space-x-2 sm:mt-4">
            <button
              onClick={handlePrev}
              className="px-3 py-2 text-sm font-medium text-white transition-colors bg-blue-600 rounded-full hover:bg-blue-700"
            >
              ‹
            </button>

            {Array.from({ length: numToShow }, (_, i) => {
              const idx = startIdx + i;
              return (
                <button
                  key={idx}
                  onClick={() => handleDotClick(idx)}
                  className={`h-2.5 w-2.5 sm:h-3 sm:w-3 rounded-full transition-all duration-300 ${
                    activeIndex === idx
                      ? "bg-blue-600 scale-125"
                      : "bg-gray-400 hover:bg-blue-300"
                  }`}
                />
              );
            })}

            <button
              onClick={handleNext}
              className="px-3 py-2 text-sm font-medium text-white transition-colors bg-blue-600 rounded-full hover:bg-blue-700"
            >
              ›
            </button>
          </div>
        )}

        {/* Description */}
        <p className="max-w-3xl mx-auto mb-10 text-sm text-center text-gray-700 sm:mb-14 sm:text-base md:text-lg">
          {description}
        </p>

        {/* Clients */}
        <h3 className="mb-5 text-xl font-semibold text-center text-blue-800 sm:text-2xl md:text-3xl sm:mb-6">
          Our Happy Customers
        </h3>

        <motion.div
          className="flex flex-wrap justify-center gap-2 px-2 sm:gap-3 md:gap-4"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
        >
          {clients.length > 0 ? (
            clients.map((c, i) => {
              // support legacy string clients and new object format { id, name, image }
              const name = typeof c === 'string' ? c : c?.name || '';
              const img = typeof c === 'string' ? '' : c?.image || '';
              return (
                <motion.span
                  key={typeof c === 'object' ? c.id || i : i}
                  className="flex items-center gap-2 px-3 py-1 text-xs font-medium text-blue-700 transition-all duration-300 bg-blue-100 rounded-full sm:px-4 sm:py-2 sm:text-sm md:text-base hover:bg-yellow-400 hover:text-white"
                  whileHover={{ scale: 1.05 }}
                >
                  {img ? (
                    <img src={`${IMAGE_BASE}/${img}`} alt={name} style={{ width: 32, height: 32, objectFit: 'cover', borderRadius: 6 }} onError={(e)=>{e.target.style.display='none'}} />
                  ) : null}
                  <span>{name}</span>
                </motion.span>
              );
            })
          ) : (
            <p className="w-full text-center text-gray-500">No clients listed yet.</p>
          )}
        </motion.div>
      </div>

      {/* Hide scrollbar */}
      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </section>
  );
};

export default Gallery;
